// Extract inputs from previous nodes
const webhookData = $json;
const promptRows = $input.all()[0].json;
const competitorRows = $input.all()[1].json;

const projectId = webhookData.project_id;
const ideaDescription = webhookData.idea_description;

// Build prompts lookup
const prompts = {};
if (Array.isArray(promptRows)) {
  promptRows.forEach(row => {
    if (row.analysis_type) {
      prompts[row.analysis_type] = row.prompt_text || row.prompt;
    }
  });
}

// Build competitor list
const competitors = [];
if (Array.isArray(competitorRows)) {
  competitorRows.forEach(row => {
    if (row.company_name) {
      competitors.push({
        name: row.company_name,
        features: row.key_features,
        pricing: row.pricing_model,
        market_position: row.market_position
      });
    }
  });
}

// Create 5 analysis items
const analysisTypes = [
  'general_web_search',
  'competitor_eval',
  'adjacent_solutions',
  'customer_rag',
  'tam_snapshot'
];

const outputs = [];
analysisTypes.forEach(analysisType => {
  const promptText = prompts[analysisType] || '';
  const replacedPrompt = promptText.replace('{idea}', ideaDescription).replace('{idea_description}', ideaDescription);

  const item = {
    analysis_type: analysisType,
    prompt_text: replacedPrompt,
    idea_description: ideaDescription,
    project_id: projectId,
    competitor_list: analysisType === 'competitor_eval' ? competitors : null
  };
  outputs.push(item);
});

return outputs;

// Route analysis items to appropriate Claude/Pinecone nodes
// This is handled by n8n's batch processing of the 5 items
// Each item will be processed through the appropriate analysis path

const analysisType = $json.analysis_type;
const output = Object.assign({}, $json);

return output;

// Merge all analysis results into a single object
// Collect all items from the previous analysis nodes

const allItems = $input.all();
const results = {
  general_web_search: null,
  competitor_eval: null,
  adjacent_solutions: null,
  customer_rag: null,
  tam_snapshot: null,
  timestamp: new Date().toISOString()
};

allItems.forEach(item => {
  const analysisType = item.json.analysis_type;
  if (item.json.body && item.json.body.content) {
    try {
      const content = item.json.body.content[0].text;
      results[analysisType] = {
        raw_response: content,
        analysis_type: analysisType
      };
    } catch (e) {
      results[analysisType] = {
        error: 'Failed to parse response',
        analysis_type: analysisType
      };
    }
  } else if (item.json.body) {
    results[analysisType] = item.json.body;
  }
});

return results;

// Compute feasibility score using CI/BI/CTI model
// Extract key metrics from the 5 analyses and call Claude for scoring

const mergedResults = $json;
const projectId = $input.all()[0].json.project_id || 'unknown';

const scoringPrompt = `
You are a product feasibility scoring expert. Analyze the following product analysis results and provide a feasibility score.

Analysis Results:
${JSON.stringify(mergedResults, null, 2)}

Score using the CI/BI/CTI model:
- Customer Impact (CI) - 30% weight: Measure breadth of customer pain, severity of problem, ease of mitigation
- Business Impact (BI) - 50% weight: New ACV potential, customer retention impact, strategic alignment, competitive advantage
- Cost to Implement (CTI) - 20% weight: Engineering complexity, team ability to execute, time to MVP

Provide JSON response with:
{
  "customer_impact": { "score": 0-10, "reasoning": "" },
  "business_impact": { "score": 0-10, "reasoning": "" },
  "cost_to_implement": { "score": 0-10, "reasoning": "" },
  "feasibility_score": 0-10,
  "go_no_go": "GO" | "NO_GO" | "INVESTIGATE",
  "executive_summary": ""
}
`;

return {
  scoring_prompt: scoringPrompt,
  project_id: projectId,
  merged_analyses: mergedResults
};

// Parse scoring response and prepare for writing to sheets
const scoringResponse = $json.body;
const projectId = $input.all()[0].json.project_id || 'unknown';
const mergedAnalyses = $input.all()[0].json.merged_analyses;

let scoreData = {};
try {
  const content = scoringResponse.content[0].text;
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    scoreData = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  scoreData = {
    error: 'Failed to parse scoring response',
    raw_response: scoringResponse.content[0].text
  };
}

// Prepare 6 rows for Google Sheets:
// 5 analysis results + 1 summary row
const rows = [];

// Row 1-5: Individual analyses
const analysisTypes = ['general_web_search', 'competitor_eval', 'adjacent_solutions', 'customer_rag', 'tam_snapshot'];
analysisTypes.forEach(type => {
  rows.push({
    project_id: projectId,
    analysis_type: type,
    results_json: JSON.stringify(mergedAnalyses[type] || {}),
    score: 'N/A',
    timestamp: new Date().toISOString()
  });
});

// Row 6: Summary with feasibility score
rows.push({
  project_id: projectId,
  analysis_type: 'feasibility_summary',
  results_json: JSON.stringify({
    ci_bi_cti: scoreData,
    all_analyses: mergedAnalyses
  }),
  score: scoreData.feasibility_score || 'N/A',
  timestamp: new Date().toISOString()
});

return { rows_to_write: rows, final_score: scoreData };

// Prepare final webhook response
const finalScore = $input.all()[0].json.final_score;
const rowsWritten = $input.all()[0].json.rows_to_write;

const response = {
  success: true,
  project_id: rowsWritten[0].project_id,
  feasibility_score: finalScore.feasibility_score || 0,
  go_no_go: finalScore.go_no_go || 'UNKNOWN',
  ci_score: finalScore.customer_impact?.score || null,
  bi_score: finalScore.business_impact?.score || null,
  cti_score: finalScore.cost_to_implement?.score || null,
  executive_summary: finalScore.executive_summary || '',
  analyses_completed: 5,
  timestamp: new Date().toISOString()
};

return response;
